#!/usr/bin/env node
/**
 * finalize-seo-origin.mjs — Deploy-time SEO finalizer
 * Generated by NoCodeExport (https://nocodeexport.vercel.app)
 *
 * Runs during your Vercel / Netlify / Cloudflare Pages build step.
 * 1. Detects your deployment URL from platform environment variables.
 * 2. Rewrites canonical / og:url / twitter:url / sitemap / robots.txt
 *    from the original crawl domain to your actual deployment URL.
 * 3. Copies all deployable files into public/ (the output directory).
 *
 * Supported platforms (env var priority):
 *   Custom override   — SITE_URL  (set manually in your platform env vars)
 *   Vercel           — VERCEL_PROJECT_PRODUCTION_URL, VERCEL_URL
 *   Netlify          — URL, DEPLOY_PRIME_URL
 *   Cloudflare Pages — CF_PAGES_URL
 *
 * Usage (manual / local preview):
 *   SITE_URL=https://www.yourdomain.com node scripts/finalize-seo-origin.mjs
 */
import { readFileSync, writeFileSync, mkdirSync, cpSync, rmSync } from 'node:fs';
import { readdirSync, statSync } from 'node:fs';
import { join } from 'node:path';

// Source origin embedded at export time
const SOURCE_ORIGIN = 'https://colorful-cake-647575.framer.app';

// Files/directories that are build artifacts — do NOT copy to public/
const BUILD_EXCLUDE = new Set([
  'scripts', 'node_modules', 'public', '.git',
  'package.json', 'package-lock.json', 'vercel.json',
  'netlify.toml', '.vercel', '.netlify',
]);

// ── Detect deploy URL from platform env ──
function detectOrigin() {
  const candidates = [
    process.env.SITE_URL,
    process.env.VERCEL_PROJECT_PRODUCTION_URL,
    process.env.VERCEL_URL,
    process.env.URL,
    process.env.DEPLOY_PRIME_URL,
    process.env.CF_PAGES_URL,
  ];
  for (const raw of candidates) {
    if (!raw) continue;
    try {
      const origin = raw.startsWith('http') ? raw : `https://${raw}`;
      return new URL(origin).origin;
    } catch { /* skip malformed */ }
  }
  return null;
}

const TARGET_ORIGIN = detectOrigin();

if (!TARGET_ORIGIN) {
  console.warn('[SEO] ⚠ No deployment URL detected. Canonical URLs keep source domain.');
  console.warn('[SEO]   Set SITE_URL=https://www.yourdomain.com in your platform env to override.');
}

if (TARGET_ORIGIN && TARGET_ORIGIN !== SOURCE_ORIGIN) {
  console.log(`[SEO] Rewriting: ${SOURCE_ORIGIN} → ${TARGET_ORIGIN}`);
} else if (TARGET_ORIGIN === SOURCE_ORIGIN) {
  console.log(`[SEO] Source and target match (${TARGET_ORIGIN}) — no rewriting needed.`);
}

// ── Rewrite SEO meta in-place (before copying) ──
function walkFiles(dir, cb) {
  let entries;
  try { entries = readdirSync(dir); } catch { return; }
  for (const entry of entries) {
    if (entry.startsWith('.') || BUILD_EXCLUDE.has(entry)) continue;
    const fullPath = join(dir, entry);
    let stat;
    try { stat = statSync(fullPath); } catch { continue; }
    if (stat.isDirectory()) walkFiles(fullPath, cb);
    else cb(fullPath, entry);
  }
}

let htmlCount = 0, sitemapFixed = false, robotsFixed = false;

if (TARGET_ORIGIN && TARGET_ORIGIN !== SOURCE_ORIGIN) {
  walkFiles('.', (filePath, name) => {
    const lower = name.toLowerCase();
    if (!lower.endsWith('.html') && name !== 'sitemap.xml' && name !== 'robots.txt') return;
    let original;
    try { original = readFileSync(filePath, 'utf8'); } catch { return; }
    const rewritten = original.replaceAll(SOURCE_ORIGIN, TARGET_ORIGIN);
    if (rewritten === original) return;
    try {
      writeFileSync(filePath, rewritten, 'utf8');
      if (lower.endsWith('.html')) htmlCount++;
      else if (name === 'sitemap.xml') sitemapFixed = true;
      else if (name === 'robots.txt') robotsFixed = true;
    } catch (e) { console.error(`[SEO] Failed to write ${filePath}: ${e.message}`); }
  });

  console.log(`[SEO] ✓ ${htmlCount} HTML file(s) rewritten`);
  if (sitemapFixed) console.log('[SEO] ✓ sitemap.xml updated');
  if (robotsFixed)  console.log('[SEO] ✓ robots.txt updated');
  console.log(`[SEO] ✓ Canonical URLs finalized → ${TARGET_ORIGIN}`);
}

// ── Copy deployable files to public/ (Vercel/Netlify output directory) ──
rmSync('public', { recursive: true, force: true });
mkdirSync('public', { recursive: true });

let copied = 0;
for (const entry of readdirSync('.')) {
  if (entry.startsWith('.') || BUILD_EXCLUDE.has(entry)) continue;
  try {
    cpSync(entry, join('public', entry), { recursive: true });
    copied++;
  } catch (e) { console.error(`[SEO] Failed to copy ${entry}: ${e.message}`); }
}

console.log(`[SEO] ✓ Copied ${copied} item(s) to public/`);
console.log('[SEO] Build complete.');
